29	/**@ch 懸賞令管理器事件*/
30	export const WANTED_POSTER_MANAGER_EVENT = {
31	    /**
32	     * @ch 設置懸賞令資料
33	     * @param IBountyData[] 懸賞令資料陣列
34	     */
35	    SET_WANTED_POSTER_DATA: "WANTED_POSTER_MANAGER_SET_WANTED_POSTER_DATA",
36	
37	    /**
38	     * @ch 設置懸賞令UI顯示狀態
39	     * @param isShow 是否顯示
40	     */
41	    SET_WANTED_POSTER_UI_SHOW: "WANTED_POSTER_MANAGER_SET_WANTED_POSTER_UI_SHOW",
42	
43	    /**
44	     * @ch 對 BaseSymbol 對應的常駐 item 播 Mark → Mark_Idle loop
45	     * @param baseSymbol number 對應的 BaseSymbol（M1~M9）
46	     * @param resolve () => void 播完 Mark 後呼叫（Mark_Idle 已在 spine 上 loop）
47	     */
48	    PLAY_MARK: "WANTED_POSTER_MANAGER_PLAY_MARK",
49	
50	    /**
51	     * @ch 對 BaseSymbol 對應的常駐 item 播 Mark_Active 並關閉 item
52	     * @param baseSymbol number 對應的 BaseSymbol
53	     * @param resolve () => void 播完 Mark_Active 且 item.active=false 後呼叫
54	     */
55	    PLAY_MARK_ACTIVE: "WANTED_POSTER_MANAGER_PLAY_MARK_ACTIVE",
56	    
57	    /**
58	     * @ch 遊戲介紹完成後顯示懸賞令x9999
