63	/**@ch 懸賞令管理器*/
64	@ccclass('WantedPosterManager')
65	export class WantedPosterManager extends Component {
66	    //#region Constants
67	    /**
68	     * @ch 需要註冊的事件列表
69	     */
70	    private static readonly EVENTS_TO_REGISTER = [
71	        WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_DATA,
72	        WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_UI_SHOW,
73	        WANTED_POSTER_MANAGER_EVENT.PLAY_MARK,
74	        WANTED_POSTER_MANAGER_EVENT.PLAY_MARK_ACTIVE,
75	        GAME_EVENT.DEVICE_ROTATION,
76	    ];
77	    //#endregion Constants
78	
79	    //#region Properties
80	    @property({
81	        type: Node,
82	        tooltip: "根節點"
83	    })
84	    private m_rootNode: Node = null;
85	
86	    @property({
87	        type: [WantedPosterItem],
88	        tooltip: "懸賞令物品"
89	    })
90	    private m_wantedPosterItems: WantedPosterItem[] = [];
91	
92	    @property({
93	        type: Layout,
94	        tooltip: "懸賞令排版元件（m_wantedPosterItems 父節點上的 cc.Layout）"
95	    })
96	    private m_layout: Layout = null;
97	
98	    @property({
99	        type: WantedPosterLayoutConfig,
100	        tooltip: "直向排版設定"
101	    })
102	    private m_portraitConfig: WantedPosterLayoutConfig = new WantedPosterLayoutConfig();
103	
104	    @property({
105	        type: WantedPosterLayoutConfig,
106	        tooltip: "橫向排版設定"
107	    })
108	    private m_landscapeConfig: WantedPosterLayoutConfig = new WantedPosterLayoutConfig();
109	    //#endregion Properties
110	
111	    //#region Variables
112	    /**@ch 是否已初始化*/
113	    private m_isInitialized: boolean = false;
114	    //#endregion Variables
115	
116	    //#region Lifecycle
117	    /**@ch 元件載入時調用*/
118	    onLoad() {
119	        this.RegisterEvent();
120	        this.RegisterKeyboardEvents();
121	    }
122	
123	    /**@ch 元件啟動時調用（GameView 已就緒，套用初始方向 Layout）*/
124	    start() {
125	        this.ApplyLayoutByOrientation();
126	    }
127	
128	    /**@ch 元件銷毀時調用*/
129	    onDestroy() {
130	        if (!this.m_isInitialized) return;
131	        this.UnregisterEvent();
132	        this.UnregisterKeyboardEvents();
133	        this.m_isInitialized = false;
134	    }
135	    //#endregion Lifecycle
136	
137	    //#region Event Management
138	    /**@ch 註冊鍵盤事件（測試用）*/
139	    private RegisterKeyboardEvents(): void {
140	        if (!DEBUG) return;
141	        // input.on(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
142	    }
143	
144	    /**@ch 取消註冊鍵盤事件（測試用）*/
145	    private UnregisterKeyboardEvents(): void {
146	        if (!DEBUG) return;
147	        // input.off(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
148	    }
149	
150	    /**@ch 註冊事件*/
151	    private RegisterEvent() {
152	        WantedPosterManager.EVENTS_TO_REGISTER.forEach(eventName => {
153	            eventManager.Register(eventName, this);
154	        });
155	        this.m_isInitialized = true;
156	    }
157	
158	    /**@ch 取消註冊事件*/
159	    private UnregisterEvent() {
160	        WantedPosterManager.EVENTS_TO_REGISTER.forEach(eventName => {
161	            eventManager.UnRegister(eventName, this);
162	        });
163	    }
164	
165	    /**
166	     * @ch 驗證 SET_WANTED_POSTER_UI_SHOW 事件參數
167	     * @param args 事件參數
168	     * @returns 是否有效
169	     */
170	    private ValidateSetWantedPosterUIShowArgs(args: any[]): boolean {
171	        if (typeof args[0] !== 'boolean') {
172	            warn('[WantedPosterManager] SET_WANTED_POSTER_UI_SHOW: 無效的參數', args[0]);
173	            return false;
174	        }
175	        return true;
176	    }
177	
178	    /**
179	     * @ch 驗證 SET_WANTED_POSTER_DATA 事件參數
180	     * @param args 事件參數
181	     * @returns 是否有效
182	     */
183	    private ValidateSetWantedPosterDataArgs(args: any[]): boolean {
184	        if (!Array.isArray(args[0])) {
185	            warn('[WantedPosterManager] SET_WANTED_POSTER_DATA: 無效的資料參數', args[0]);
186	            return false;
187	        }
188	        return true;
189	    }
190	
191	    /**
192	     * @ch 事件回調
193	     * @param event 事件名稱
194	     * @param args 事件參數
195	     */
196	    OnEvent(event: string, ...args: any[]) {
197	        switch (event) {
198	            case WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_DATA:
199	                if (this.ValidateSetWantedPosterDataArgs(args)) {
200	                    this.SetWantedPosterData(args[0] as IBountyData[]);
201	                }
202	                break;
203	
204	            case WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_UI_SHOW:
205	                if (this.ValidateSetWantedPosterUIShowArgs(args)) {
206	                    this.SetWantedPosterUIShow(args[0] as boolean);
207	                }
208	                break;
209	
210	            case WANTED_POSTER_MANAGER_EVENT.PLAY_MARK:
211	                this.HandlePlayMark(args[0] as number, args[1] as () => void);
212	                break;
213	
214	            case WANTED_POSTER_MANAGER_EVENT.PLAY_MARK_ACTIVE:
215	                this.HandlePlayMarkActive(args[0] as number, args[1] as () => void);
216	                break;
217	
218	            case GAME_EVENT.DEVICE_ROTATION:
219	                this.ApplyLayoutByOrientation();
220	                break;
221	
222	            default:
223	                warn('[WantedPosterManager] OnEvent: 未知的事件', event);
224	        }
225	    }
226	
227	    /**
228	     * @ch 依目前裝置方向套用對應的 Layout 設定
229	     * 由 start() 與 GAME_EVENT.DEVICE_ROTATION 事件觸發
230	     */
231	    private ApplyLayoutByOrientation(): void {
232	        if (!this.m_layout) {
233	            warn('[WantedPosterManager] ApplyLayoutByOrientation: m_layout 未設置');
234	            return;
235	        }
236	        const isLandscape = Common.GetGameView().IsLandscape;
237	        const cfg = isLandscape ? this.m_landscapeConfig : this.m_portraitConfig;
238	
239	        this.m_layout.type = cfg.type;
240	        this.m_layout.resizeMode = cfg.resizeMode;
241	        this.m_layout.paddingLeft = cfg.paddingLeft;
242	        this.m_layout.paddingRight = cfg.paddingRight;
243	        this.m_layout.paddingTop = cfg.paddingTop;
244	        this.m_layout.paddingBottom = cfg.paddingBottom;
245	        this.m_layout.spacingX = cfg.spacingX;
246	        this.m_layout.spacingY = cfg.spacingY;
247	        this.m_layout.alignHorizontal = cfg.alignHorizontal;
248	        this.m_layout.alignVertical = cfg.alignVertical;
249	        this.m_layout.updateLayout();
250	    }
251	
252	    /**
253	     * @ch 處理 PLAY_MARK 事件
254	     * BC-4：對該 BaseSymbol 的所有相符常駐 item 同時播 Mark，全部完成才 resolve
255	     *       （找到 N 個就播 N 個；N=0 才視為 EH-1，0<N 屬可接受降級不 warn）
256	     * EH-1：找不到任何對應 item（空陣列）→ warn + 立刻 resolve（不阻斷上游流程）
257	     * EH-9：resolve callback 缺失 → error（caller bug）
258	     */
259	    private HandlePlayMark(baseSymbol: number, resolve: () => void) {
260	        if (typeof resolve !== 'function') {
261	            warn('[WantedPosterManager] PLAY_MARK: resolve callback 缺失');
262	            return;
263	        }
264	        const items = this.GetItemsByBaseSymbol(baseSymbol);
265	        if (items.length === 0) {
266	            warn('[WantedPosterManager] PLAY_MARK: 找不到對應 item, baseSymbol=', baseSymbol);
267	            resolve();
268	            return;
269	        }
270	        Promise.all(items.map(item => item.PlayMark())).then(() => resolve());
271	    }
272	
273	    /**
274	     * @ch 處理 PLAY_MARK_ACTIVE 事件
275	     * BC-6：對該 BaseSymbol 的所有相符 item 同時播 Mark_Active 並各自 active=false
276	     * EH-1：找不到任何對應 item（空陣列）→ warn + 立刻 resolve
277	     * EH-9：resolve callback 缺失 → error
278	     */
279	    private HandlePlayMarkActive(baseSymbol: number, resolve: () => void) {
280	        if (typeof resolve !== 'function') {
281	            warn('[WantedPosterManager] PLAY_MARK_ACTIVE: resolve callback 缺失');
282	            return;
283	        }
284	        const items = this.GetItemsByBaseSymbol(baseSymbol);
285	        if (items.length === 0) {
286	            warn('[WantedPosterManager] PLAY_MARK_ACTIVE: 找不到對應 item, baseSymbol=', baseSymbol);
287	            resolve();
288	            return;
289	        }
290	        Promise.all(items.map(item =>
291	            item.PlayMarkActive().then(() => { item.node.active = false; })
292	        )).then(() => resolve());
293	    }
294	    //#endregion Event Management
295	
296	    //#region Methods
297	    /**
298	     * @ch 設置懸賞令資料（前後狀態比對 — 決定 In / Out / 僅更新）
299	     *
300	     * BC-1：item 從 inactive→active(Multiple>0) → SetData + active=true + PlayIn
301	     * BC-2：item 從 active→inactive(Multiple<=0) → PlayOut → active=false
302	     * BC-12：BaseSymbol 不變 → 僅更新 multiplier label（不重播 In）
303	     * BC-13：顯示數量少→多（原本有顯示且本輪變多）→ 先讓現有全部 Out，再讓新的全部一起 In（協調進場）
304	     * EH-6：BaseSymbol 變動但仍 active → PlayOut → 重設資料 → PlayIn
305	     */
306	    private SetWantedPosterData(dataList: IBountyData[]) {
307	        if (!this.m_wantedPosterItems || this.m_wantedPosterItems.length === 0) {
308	            warn('[WantedPosterManager] SetWantedPosterData: 懸賞令物品未設置');
309	            return;
310	        }
311	
312	        if (dataList.length > this.m_wantedPosterItems.length) {
313	            warn('[WantedPosterManager] SetWantedPosterData: 資料數量超過物品數量',
314	                dataList.length, '>', this.m_wantedPosterItems.length);
315	        }
316	
317	        const count = this.m_wantedPosterItems.length;
318	
319	        // BC-13：少→多協調轉場偵測——統計前後顯示數量
320	        let prevActiveCount = 0;
321	        let newActiveCount = 0;
322	        for (let i = 0; i < count; i++) {
323	            const item = this.m_wantedPosterItems[i];
324	            if (!item) continue;
325	            if (item.node.active) prevActiveCount++;
326	            const d = i < dataList.length ? dataList[i] : null;
327	            if (d !== null && d.Multiple > 0) newActiveCount++;
328	        }
329	        // 原本有顯示且本輪變多 → 走協調轉場（現有全 Out → 新的全一起 In），不走下方逐 item 比對
330	        if (prevActiveCount > 0 && newActiveCount > prevActiveCount) {
331	            this.PlayFewerToMoreTransition(dataList);
332	            return;
333	        }
334	
335	        for (let i = 0; i < count; i++) {
336	            const item = this.m_wantedPosterItems[i];
337	            if (!item) continue;
338	
339	            const prevActive = item.node.active;
340	            const prevBaseSymbol = prevActive ? item.GetBaseSymbol() : Symbol.MAX;
341	            const newData: IBountyData | null = i < dataList.length ? dataList[i] : null;
342	            const newActive = newData !== null && newData.Multiple > 0;
343	
344	            if (!newActive) {
345	                // 本輪不顯示
346	                if (prevActive) {
347	                    // BC-2：上輪有顯示 → 播 Out 後關閉
348	                    item.PlayOut().then(() => { item.node.active = false; });
349	                }
350	                // else：原本就沒顯示，不動
351	                continue;
352	            }
353	
354	            // 本輪要顯示
355	            if (!prevActive) {
356	                // BC-1：上輪沒顯示 → 設資料、active=true、PlayIn (fire-and-forget)
357	                item.SetWantedPosterData(newData);
358	                item.node.active = true;
359	                item.PlayIn();
360	            } else if (prevBaseSymbol !== newData.BaseSymbol) {
361	                // EH-6：BaseSymbol 變動 → 先 Out 再 In
362	                item.PlayOut().then(() => {
363	                    item.SetWantedPosterData(newData);
364	                    item.PlayIn();
365	                });
366	            } else {
367	                // BC-12：BaseSymbol 同 → 僅更新 multiplier label
368	                item.SetWantedPosterData(newData);
369	            }
370	        }
371	    }
372	
373	    /**
374	     * @ch BC-13 少→多協調轉場：先讓所有現有 active item 播 Out 並關閉，
375	     *     全部完成後再對所有新 active item 設資料、active=true、一起 PlayIn。
376	     *     取代逐 item 獨立進場，避免 Layout 重排造成舊 item 位置跳動。
377	     */
378	    private PlayFewerToMoreTransition(dataList: IBountyData[]) {
379	        const count = this.m_wantedPosterItems.length;
380	
381	        // 1) 現有全部 Out → 關閉（prevActiveCount > 0 已由 caller 保證 outPromises 非空）
382	        const outPromises: Promise<void>[] = [];
383	        for (const item of this.m_wantedPosterItems) {
384	            if (item && item.node.active) {
385	                outPromises.push(item.PlayOut().then(() => { item.node.active = false; }));
386	            }
387	        }
388	
389	        // 2) 全部 Out 完成後，新的全部一起設資料並 PlayIn
390	        Promise.all(outPromises).then(() => {
391	            for (let i = 0; i < count; i++) {
392	                const item = this.m_wantedPosterItems[i];
393	                if (!item) continue;
394	                const newData = i < dataList.length ? dataList[i] : null;
395	                if (newData === null || newData.Multiple <= 0) continue;
396	                item.SetWantedPosterData(newData);
397	                item.node.active = true;
398	                item.PlayIn();
399	            }
400	        });
401	    }
402	
403	    /**
404	     * @ch 依 BaseSymbol 取得**所有**相符的 active 常駐 item（內部用，PLAY_MARK / PLAY_MARK_ACTIVE 路徑）
405	     * 同一盤面允許多筆同 BaseSymbol bounty（各自設到不同 index 的 item），故回陣列而非單一
406	     */
