async Play (
    spineType: BS_SPINE_TYPE,
    animName: string,
    isLoop: boolean = false,
    endCB?: () => void,
    eventCB?: (eventName: string) => void
)
{
    this.DoTargetAction( spineType, async spine =>
    {
        if ( spineType === BS_SPINE_TYPE.CANNON )
        {
            //砲台動畫需要加上前綴(橫直版)
            if(this.m_isLandscape)
            {
                animName = "H_" + animName;
            }
            else
            {
                animName = "S_" + animName;
            }
            log({animName: animName});
        }
        else
        {
            //角色動畫不循環
            isLoop = false;
        }


        await spine.PlayAnimation( animName, spine.Spine, isLoop, undefined, eventCB );
        endCB?.();


        //角色動畫後須後處理其他動作
        if(spineType === BS_SPINE_TYPE.CHARACTER)
        {
            switch ( animName )
